const response = $input.first().json;
const reportText = response.content?.[0]?.text || 'Error: No content in Claude response';
const date = new Date().toISOString().split('T')[0];
const timestamp = new Date().toLocaleString('en-AU', { timeZone: 'Australia/Brisbane' });

const fullReport = `# Majorka Daily Research Report\n**Generated:** ${timestamp} (AEST)\n**Model:** ${response.model}\n---\n\n${reportText}`;

return [{
  json: {
    reportText: fullReport,
    date,
    filename: `majorka-research-${date}.md`,
    model: response.model,
    tokens: response.usage
  }
}];

// Requires NODE_FUNCTION_ALLOW_BUILTIN=fs,path in n8n environment
const fs = require('fs');
const path = require('path');

const { reportText, date, filename } = $input.first().json;

// Save inside n8n's data directory (persisted via Docker volume)
const outputDir = path.join('/home/node/.n8n', 'reports');
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

const filepath = path.join(outputDir, filename);
fs.writeFileSync(filepath, reportText, 'utf8');

// Also overwrite a 'latest' symlink for easy access
const latestPath = path.join(outputDir, 'majorka-research-latest.md');
if (fs.existsSync(latestPath)) fs.unlinkSync(latestPath);
fs.writeFileSync(latestPath, reportText, 'utf8');

return [{
  json: {
    success: true,
    filepath,
    latestPath,
    date,
    preview: reportText.substring(0, 300) + '...'
  }
}];
